import Vue from "vue";

import MonitoringInterface from "@/views/MonitoringInterface.vue";
import Setting from "@/views/Setting.vue";
import History from "@/views/History.vue";
import ExportData from "@/views/ExportData.vue";
import CalibrateSensor from "@/views/CalibrateSensor.vue";
// 引入路由
import VueRouter from "vue-router";

Vue.use(VueRouter); // 引入路由插件

const router = new VueRouter({
  routes: [
    { path: "/MonitoringInterface", component: MonitoringInterface },
    { path: "/Setting", component: Setting },
    { path: "/History", component: History },
    { path: "/ExportData", component: ExportData },
    { path: "/CalibrateSensor", component: CalibrateSensor },
  ],
});

export default router;
